<template>
  <div v-if="isOpen" class="modal-overlay" @click="handleOverlayClick">
    <div class="modal-container" @click.stop>
      <div class="modal-header">
        <div class="modal-title-group">
          <h3 class="modal-title">チャット履歴</h3>
          <p class="modal-subtitle" v-if="inquiry">
            {{ inquiry.title }} - {{ inquiry.customerName }}
          </p>
        </div>
        <button @click="closeModal" class="modal-close">
          <span>×</span>
        </button>
      </div>

      <div class="modal-body">
        <!-- ローディング状態 -->
        <div v-if="loading" class="loading-state">
          <div class="loading-spinner"></div>
          <p>チャット履歴を読み込み中...</p>
        </div>

        <!-- エラー状態 -->
        <div v-else-if="error" class="error-state">
          <div class="error-icon">⚠️</div>
          <p class="error-message">{{ error }}</p>
          <button @click="fetchChatHistory" class="btn btn-primary btn-sm">
            再読み込み
          </button>
        </div>

        <!-- チャット履歴表示 -->
        <div v-else-if="chatHistory.length > 0" class="chat-container">
          <div 
            v-for="message in chatHistory" 
            :key="message.id"
            class="chat-message"
            :class="{ 
              'sent': message.sender === 'franchise',
              'received': message.sender !== 'franchise'
            }"
          >
            <div class="message-avatar">
              <span v-if="message.sender === 'franchise'">🏢</span>
              <span v-else-if="message.sender === 'customer'">👤</span>
              <span v-else>🤖</span>
            </div>
            
            <div class="message-content">
              <div class="message-header">
                <span class="sender-name">{{ getSenderName(message.sender) }}</span>
                <span class="message-time">{{ formatTime(message.timestamp) }}</span>
              </div>
              
              <div class="message-text">{{ message.content }}</div>
              
              <!-- 添付ファイルがある場合 -->
              <div v-if="message.attachments && message.attachments.length > 0" class="message-attachments">
                <div 
                  v-for="attachment in message.attachments" 
                  :key="attachment.id"
                  class="attachment-item"
                >
                  <span class="attachment-icon">📎</span>
                  <a :href="attachment.url" target="_blank" class="attachment-link">
                    {{ attachment.name }}
                  </a>
                </div>
              </div>
              
              <!-- 読み取り状況 -->
              <div v-if="message.readAt" class="message-status">
                <span class="read-status">既読 {{ formatTime(message.readAt) }}</span>
              </div>
            </div>
          </div>
        </div>

        <!-- チャット履歴なし -->
        <div v-else class="empty-state">
          <div class="empty-icon">💬</div>
          <p class="empty-message">まだチャット履歴がありません</p>
          <p class="empty-description">
            顧客とのやり取りが開始されると、ここに履歴が表示されます。
          </p>
        </div>
      </div>

      <div class="modal-footer">
        <div class="chat-stats" v-if="chatHistory.length > 0">
          <span class="stat-item">
            📊 総メッセージ数: {{ chatHistory.length }}
          </span>
          <span class="stat-item">
            📅 最終更新: {{ getLastMessageTime() }}
          </span>
        </div>
        
        <div class="modal-actions">
          <button @click="exportChatHistory" class="btn btn-outline btn-sm" :disabled="chatHistory.length === 0">
            📄 エクスポート
          </button>
          <button @click="closeModal" class="btn btn-secondary">
            閉じる
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch } from 'vue'
import { apiService } from '@/services/api'

const props = defineProps({
  isOpen: {
    type: Boolean,
    default: false
  },
  inquiry: {
    type: Object,
    default: null
  }
})

const emit = defineEmits(['close'])

// State
const chatHistory = ref([])
const loading = ref(false)
const error = ref('')

// Methods
const closeModal = () => {
  emit('close')
}

const handleOverlayClick = () => {
  closeModal()
}

const fetchChatHistory = async () => {
  if (!props.inquiry?.id) return

  try {
    loading.value = true
    error.value = ''

    const response = await apiService.post('/getChatHistoryForInquiry', {
      inquiryId: props.inquiry.id
    })

    if (response.success) {
      chatHistory.value = response.data || []
    } else {
      throw new Error(response.message || 'チャット履歴の取得に失敗しました')
    }
  } catch (err) {
    error.value = err.message
    console.error('Error fetching chat history:', err)
  } finally {
    loading.value = false
  }
}

const getSenderName = (sender) => {
  switch (sender) {
    case 'franchise':
      return '加盟店'
    case 'customer':
      return '顧客'
    case 'system':
      return 'システム'
    default:
      return sender
  }
}

const formatTime = (timestamp) => {
  if (!timestamp) return ''
  
  const date = new Date(timestamp)
  const now = new Date()
  const diffInHours = Math.abs(now - date) / (1000 * 60 * 60)
  
  if (diffInHours < 24) {
    // 24時間以内なら時間のみ
    return date.toLocaleTimeString('ja-JP', {
      hour: '2-digit',
      minute: '2-digit'
    })
  } else if (diffInHours < 24 * 7) {
    // 1週間以内なら曜日と時間
    return date.toLocaleDateString('ja-JP', {
      weekday: 'short',
      hour: '2-digit',
      minute: '2-digit'
    })
  } else {
    // それ以上なら日付と時間
    return date.toLocaleDateString('ja-JP', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    })
  }
}

const getLastMessageTime = () => {
  if (chatHistory.value.length === 0) return ''
  
  const lastMessage = chatHistory.value[chatHistory.value.length - 1]
  return formatTime(lastMessage.timestamp)
}

const exportChatHistory = () => {
  if (chatHistory.value.length === 0) return

  // CSV形式でエクスポート
  const headers = ['送信者', '内容', '送信時刻']
  const csvContent = [
    headers.join(','),
    ...chatHistory.value.map(message => [
      getSenderName(message.sender),
      `"${message.content.replace(/"/g, '""')}"`,
      formatTime(message.timestamp)
    ].join(','))
  ].join('\n')

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' })
  const link = document.createElement('a')
  const url = URL.createObjectURL(blob)
  
  link.setAttribute('href', url)
  link.setAttribute('download', `chat_history_${props.inquiry?.id}_${new Date().toISOString().split('T')[0]}.csv`)
  link.style.visibility = 'hidden'
  
  document.body.appendChild(link)
  link.click()
  document.body.removeChild(link)
}

// Watch for modal open/close
watch(() => props.isOpen, (newValue) => {
  if (newValue && props.inquiry?.id) {
    fetchChatHistory()
  } else {
    chatHistory.value = []
    error.value = ''
  }
})

// Watch for inquiry changes
watch(() => props.inquiry?.id, (newId) => {
  if (newId && props.isOpen) {
    fetchChatHistory()
  }
})
</script>

