import { defineStore } from 'pinia'
import { ref } from 'vue'
import { apiService } from '@/services/api'

export const useNotificationsStore = defineStore('notifications', () => {
  
  // State
  const settings = ref({
    line: {
      enabled: false,
      webhookUrl: '',
      newInquiry: true,
      statusUpdate: true,
      billing: true,
      urgent: true
    },
    email: {
      enabled: true,
      address: '',
      newInquiry: true,
      statusUpdate: true,
      billing: true,
      urgent: true,
      maintenance: false
    },
    sms: {
      enabled: false,
      phoneNumber: '',
      urgent: true,
      paymentDue: true
    },
    timeRange: {
      start: 9,
      end: 18,
      timezone: 'Asia/Tokyo'
    },
    frequency: {
      immediate: true,
      daily: false,
      weekly: false
    }
  })

  const loading = ref(false)
  const error = ref('')
  const saveStatus = ref('')

  // Actions
  const fetchNotificationSettings = async (childId) => {
    try {
      loading.value = true
      error.value = ''
      
      const response = await apiService.post('/getNotificationSettings', {
        childId: childId
      })

      if (response.success) {
        // デフォルト設定とマージ
        settings.value = {
          ...settings.value,
          ...response.data
        }
      } else {
        throw new Error(response.error || '通知設定の取得に失敗しました')
      }
    } catch (err) {
      error.value = err.message
      console.error('Error fetching notification settings:', err)
    } finally {
      loading.value = false
    }
  }

  const updateNotificationSettings = async (childId, newSettings) => {
    try {
      loading.value = true
      error.value = ''
      saveStatus.value = 'saving'
      
      const response = await apiService.post('/updateNotificationSettings', {
        childId: childId,
        settings: newSettings || settings.value
      })

      if (response.success) {
        if (newSettings) {
          settings.value = { ...settings.value, ...newSettings }
        }
        saveStatus.value = 'saved'
        
        // 3秒後にステータスをクリア
        setTimeout(() => {
          saveStatus.value = ''
        }, 3000)
        
        return true
      } else {
        throw new Error(response.error || '通知設定の保存に失敗しました')
      }
    } catch (err) {
      error.value = err.message
      saveStatus.value = 'error'
      console.error('Error updating notification settings:', err)
      return false
    } finally {
      loading.value = false
    }
  }

  const testNotification = async (childId, type) => {
    try {
      const response = await apiService.post('/testNotification', {
        childId: childId,
        type: type // 'line', 'slack', 'email', 'sms'
      })

      if (response.success) {
        return { success: true, message: 'テスト通知を送信しました' }
      } else {
        throw new Error(response.error || 'テスト通知の送信に失敗しました')
      }
    } catch (err) {
      console.error('Error sending test notification:', err)
      return { success: false, message: err.message }
    }
  }

  const validateSettings = () => {
    const errors = []

    // LINE設定の検証
    if (settings.value.line.enabled && !settings.value.line.webhookUrl) {
      errors.push('LINE Webhook URLが設定されていません')
    }

    // Slack設定の検証
    if (settings.value.slack.enabled && !settings.value.slack.webhookUrl) {
      errors.push('Slack Webhook URLが設定されていません')
    }

    // メール設定の検証
    if (settings.value.email.enabled && !settings.value.email.address) {
      errors.push('メールアドレスが設定されていません')
    }

    // SMS設定の検証
    if (settings.value.sms.enabled && !settings.value.sms.phoneNumber) {
      errors.push('SMS用電話番号が設定されていません')
    }

    // 時間範囲の検証
    if (settings.value.timeRange.start >= settings.value.timeRange.end) {
      errors.push('通知時間の設定が正しくありません')
    }

    return errors
  }

  const updateLineSettings = (lineSettings) => {
    settings.value.line = { ...settings.value.line, ...lineSettings }
  }

  const updateSlackSettings = (slackSettings) => {
    settings.value.slack = { ...settings.value.slack, ...slackSettings }
  }

  const updateEmailSettings = (emailSettings) => {
    settings.value.email = { ...settings.value.email, ...emailSettings }
  }

  const updateSmsSettings = (smsSettings) => {
    settings.value.sms = { ...settings.value.sms, ...smsSettings }
  }

  const updateTimeSettings = (timeSettings) => {
    settings.value.timeRange = { ...settings.value.timeRange, ...timeSettings }
  }

  const updateFrequencySettings = (frequencySettings) => {
    settings.value.frequency = { ...settings.value.frequency, ...frequencySettings }
  }

  const resetToDefaults = () => {
    settings.value = {
      line: {
        enabled: false,
        webhookUrl: '',
        newInquiry: true,
        statusUpdate: true,
        billing: true,
        urgent: true
      },
      slack: {
        enabled: false,
        webhookUrl: '',
        channel: '',
        newInquiry: true,
        statusUpdate: false,
        billing: true,
        urgent: true
      },
      email: {
        enabled: true,
        address: '',
        newInquiry: true,
        statusUpdate: true,
        billing: true,
        urgent: true,
        maintenance: false
      },
      sms: {
        enabled: false,
        phoneNumber: '',
        urgent: true,
        paymentDue: true
      },
      timeRange: {
        start: 9,
        end: 18,
        timezone: 'Asia/Tokyo'
      },
      frequency: {
        immediate: true,
        daily: false,
        weekly: false
      }
    }
  }

  const clearError = () => {
    error.value = ''
  }

  const clearSaveStatus = () => {
    saveStatus.value = ''
  }

  // Helper functions
  const isAnyNotificationEnabled = () => {
    return settings.value.line.enabled || 
           settings.value.email.enabled || 
           settings.value.sms.enabled
  }

  const getEnabledNotificationTypes = () => {
    const types = []
    if (settings.value.line.enabled) types.push('LINE')
    if (settings.value.email.enabled) types.push('メール')
    if (settings.value.sms.enabled) types.push('SMS')
    return types
  }

  return {
    // State
    settings,
    loading,
    error,
    saveStatus,
    
    // Actions
    fetchNotificationSettings,
    updateNotificationSettings,
    testNotification,
    validateSettings,
    updateLineSettings,
    updateSlackSettings,
    updateEmailSettings,
    updateSmsSettings,
    updateTimeSettings,
    updateFrequencySettings,
    resetToDefaults,
    clearError,
    clearSaveStatus,
    isAnyNotificationEnabled,
    getEnabledNotificationTypes
  }
})