<template>
  <div class="today-schedule">
    <div class="schedule-header">
      <h3 class="section-title">
        <span class="title-icon">📅</span>
        今日の予定
        <span class="schedule-count">({{ totalTasks }})</span>
      </h3>
      
      <div class="schedule-actions">
        <button @click="refreshSchedule" class="refresh-btn" :disabled="isLoading">
          <span v-if="isLoading" class="loading-spinner"></span>
          <span v-else>🔄</span>
        </button>
        <button @click="$emit('open-calendar')" class="calendar-btn">
          📅 カレンダー
        </button>
      </div>
    </div>
    
    <!-- 予定サマリー -->
    <div class="schedule-summary">
      <div class="summary-stats">
        <div class="stat-item" :class="{ active: summaryFilter === 'all' }" @click="setSummaryFilter('all')">
          <span class="stat-number">{{ totalTasks }}</span>
          <span class="stat-label">全予定</span>
        </div>
        <div class="stat-item" :class="{ active: summaryFilter === 'pending' }" @click="setSummaryFilter('pending')">
          <span class="stat-number">{{ pendingTasks }}</span>
          <span class="stat-label">未完了</span>
        </div>
        <div class="stat-item" :class="{ active: summaryFilter === 'urgent' }" @click="setSummaryFilter('urgent')">
          <span class="stat-number">{{ urgentTasks }}</span>
          <span class="stat-label">緊急</span>
        </div>
      </div>
    </div>
    
    <!-- 予定リスト -->
    <div v-if="filteredSchedule.length === 0" class="empty-schedule">
      <div class="empty-icon">📅</div>
      <p v-if="summaryFilter === 'all'">今日の予定はありません</p>
      <p v-else-if="summaryFilter === 'pending'">未完了の予定はありません</p>
      <p v-else>緊急の予定はありません</p>
      <button @click="$emit('add-schedule')" class="add-schedule-btn">
        ➕ 予定を追加
      </button>
    </div>
    
    <div v-else class="schedule-list">
      <div
        v-for="item in filteredSchedule"
        :key="item.id"
        class="schedule-item"
        :class="[item.type, { 
          completed: item.completed, 
          urgent: item.urgent,
          overdue: isOverdue(item)
        }]"
      >
        <!-- 時間とステータス -->
        <div class="schedule-time">
          <span class="time-text">{{ formatTime(item.time) }}</span>
          <span v-if="item.duration" class="duration-text">{{ item.duration }}分</span>
          <div class="status-indicators">
            <span v-if="item.urgent" class="urgent-badge">🚨</span>
            <span v-if="isOverdue(item)" class="overdue-badge">⏰</span>
            <span v-if="item.completed" class="completed-badge">✅</span>
          </div>
        </div>
        
        <!-- 予定詳細 -->
        <div class="schedule-details">
          <h5 class="schedule-title">
            <span class="type-icon">{{ getTypeIcon(item.type) }}</span>
            {{ item.title }}
          </h5>
          <p class="schedule-customer">
            <span class="customer-icon">👤</span>
            {{ item.customer }}
          </p>
          <p v-if="item.location" class="schedule-location">
            <span class="location-icon">📍</span>
            {{ item.location }}
          </p>
          <p v-if="item.notes" class="schedule-notes">
            <span class="notes-icon">📝</span>
            {{ item.notes }}
          </p>
        </div>
        
        <!-- アクションボタン -->
        <div class="schedule-actions">
          <button 
            v-if="!item.completed"
            @click="executeAction(item)" 
            class="action-btn primary"
            :class="item.type"
          >
            {{ getActionLabel(item.type) }}
          </button>
          
          <button 
            v-if="!item.completed"
            @click="markAsCompleted(item)" 
            class="action-btn complete"
          >
            ✅
          </button>
          
          <button 
            @click="editSchedule(item)" 
            class="action-btn edit"
          >
            ✏️
          </button>
          
          <button 
            @click="showScheduleMenu(item, $event)" 
            class="action-btn menu"
            ref="menuButton"
          >
            ⋯
          </button>
        </div>
      </div>
    </div>
    
    <!-- 次の予定プレビュー -->
    <div v-if="nextScheduleItem" class="next-schedule">
      <h4>次の予定</h4>
      <div class="next-item">
        <span class="next-time">{{ formatTime(nextScheduleItem.time) }}</span>
        <span class="next-title">{{ nextScheduleItem.title }}</span>
        <span class="next-customer">{{ nextScheduleItem.customer }}</span>
      </div>
    </div>
    
    <!-- 予定メニュー -->
    <div v-if="showMenu" class="schedule-menu" :style="menuPosition">
      <button @click="rescheduleItem" class="menu-item">
        🕐 時間変更
      </button>
      <button @click="duplicateItem" class="menu-item">
        📋 複製
      </button>
      <button @click="shareItem" class="menu-item">
        📤 共有
      </button>
      <button @click="deleteItem" class="menu-item danger">
        🗑️ 削除
      </button>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch, onMounted, onUnmounted } from 'vue'

const props = defineProps({
  schedule: {
    type: Array,
    default: () => []
  },
  loading: {
    type: Boolean,
    default: false
  }
})

const emit = defineEmits([
  'refresh',
  'execute-action',
  'mark-completed',
  'edit-schedule',
  'add-schedule',
  'open-calendar',
  'reschedule',
  'duplicate',
  'share',
  'delete'
])

// リアクティブデータ
const isLoading = ref(false)
const summaryFilter = ref('all')
const showMenu = ref(false)
const selectedMenuItem = ref(null)
const menuPosition = ref({})

// 計算プロパティ
const totalTasks = computed(() => props.schedule.length)
const pendingTasks = computed(() => props.schedule.filter(item => !item.completed).length)
const urgentTasks = computed(() => props.schedule.filter(item => item.urgent && !item.completed).length)

const filteredSchedule = computed(() => {
  let filtered = props.schedule
  
  switch (summaryFilter.value) {
    case 'pending':
      filtered = filtered.filter(item => !item.completed)
      break
    case 'urgent':
      filtered = filtered.filter(item => item.urgent && !item.completed)
      break
    default:
      // 'all' - フィルターなし
      break
  }
  
  // 時間順にソート
  return filtered.sort((a, b) => {
    const timeA = new Date(`2024-01-01T${a.time}`)
    const timeB = new Date(`2024-01-01T${b.time}`)
    return timeA - timeB
  })
})

const nextScheduleItem = computed(() => {
  const now = new Date()
  const currentTime = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`
  
  const upcomingItems = props.schedule.filter(item => 
    !item.completed && item.time > currentTime
  ).sort((a, b) => {
    const timeA = new Date(`2024-01-01T${a.time}`)
    const timeB = new Date(`2024-01-01T${b.time}`)
    return timeA - timeB
  })
  
  return upcomingItems[0] || null
})

// メソッド
const refreshSchedule = async () => {
  isLoading.value = true
  try {
    emit('refresh')
    await new Promise(resolve => setTimeout(resolve, 1000)) // 模擬的な遅延
  } finally {
    isLoading.value = false
  }
}

const setSummaryFilter = (filter) => {
  summaryFilter.value = filter
}

const formatTime = (time) => {
  return time || '--:--'
}

const getTypeIcon = (type) => {
  const icons = {
    call: '📞',
    visit: '🏠',
    meeting: '💼',
    contract: '📄',
    survey: '🔍',
    followup: '🔄',
    other: '📌'
  }
  return icons[type] || '📌'
}

const getActionLabel = (type) => {
  const labels = {
    call: '電話する',
    visit: '出発',
    meeting: '開始',
    contract: '契約',
    survey: '調査',
    followup: 'フォロー',
    other: '実行'
  }
  return labels[type] || '実行'
}

const isOverdue = (item) => {
  if (item.completed) return false
  
  const now = new Date()
  const currentTime = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`
  
  return item.time < currentTime
}

const executeAction = (item) => {
  emit('execute-action', item)
}

const markAsCompleted = (item) => {
  emit('mark-completed', item)
}

const editSchedule = (item) => {
  emit('edit-schedule', item)
}

const showScheduleMenu = (item, event) => {
  selectedMenuItem.value = item
  showMenu.value = true
  
  // メニューの位置を計算
  if (event && event.target) {
    const rect = event.target.getBoundingClientRect()
    menuPosition.value = {
      top: `${rect.bottom + 5}px`,
      left: `${rect.left - 100}px`
    }
  } else {
    // フォールバック位置
    menuPosition.value = {
      top: '200px',
      left: '200px'
    }
  }
}

const rescheduleItem = () => {
  emit('reschedule', selectedMenuItem.value)
  closeMenu()
}

const duplicateItem = () => {
  emit('duplicate', selectedMenuItem.value)
  closeMenu()
}

const shareItem = () => {
  emit('share', selectedMenuItem.value)
  closeMenu()
}

const deleteItem = () => {
  if (confirm('この予定を削除しますか？')) {
    emit('delete', selectedMenuItem.value)
  }
  closeMenu()
}

const closeMenu = () => {
  showMenu.value = false
  selectedMenuItem.value = null
}

// クリック外でメニューを閉じる
const handleClickOutside = (event) => {
  if (showMenu.value && !event.target.closest('.schedule-menu')) {
    closeMenu()
  }
}

// ライフサイクル
onMounted(() => {
  document.addEventListener('click', handleClickOutside)
})

onUnmounted(() => {
  document.removeEventListener('click', handleClickOutside)
})

// ウォッチャー
watch(() => props.loading, (newValue) => {
  isLoading.value = newValue
})
</script>

