            <span>リマインダーを設定</span>
          </label>
          
          <div v-if="reminder.enabled" class="reminder-details">
            <div class="reminder-time">
              <label>通知タイミング:</label>
              <select v-model="reminder.before" class="reminder-select">
                <option value="15">15分前</option>
                <option value="30">30分前</option>
                <option value="60">1時間前</option>
                <option value="120">2時間前</option>
                <option value="1440">前日</option>
              </select>
            </div>
            
            <div class="reminder-method">
