          @click="scheduleVisit" 
          class="btn btn-primary btn-lg"
          :disabled="!isFormValid || isScheduling"
        >
          <span v-if="isScheduling" class="loading-spinner"></span>
          <span v-else class="btn-icon">🏠</span>
          訪問予定を設定
        </button>
      </div>
