</template>

<script setup>
import { ref, computed, watch, onMounted } from 'vue'

const props = defineProps({
  show: Boolean,
  case: Object
})

const emit = defineEmits(['close', 'visit-scheduled'])

// リアクティブデータ
const selectedVisitType = ref(null)
const visitDate = ref('')
const selectedTimeSlot = ref(null)
const customTime = ref('')
const visitDuration = ref('60')
const customDuration = ref('')
const selectedPreparations = ref([])
const visitMemo = ref('')
const isScheduling = ref(false)

const reminder = ref({
  enabled: true,
  before: 30,
  methods: {
    push: true,
    email: false,
    sms: false
  }
})

// 訪問タイプ
const visitTypes = [
  { id: 'survey', icon: '🔍', label: '現地調査' },
  { id: 'estimate', icon: '📋', label: '見積説明' },
  { id: 'contract', icon: '📄', label: '契約手続き' },
  { id: 'consultation', icon: '💬', label: '相談・打合せ' },
  { id: 'followup', icon: '🔄', label: 'フォローアップ' },
  { id: 'other', icon: '❓', label: 'その他' }
]

// 時間帯スロット
const timeSlots = [
  { value: 'morning', label: '午前中', period: '9:00-12:00' },
  { value: 'afternoon', label: '午後', period: '13:00-17:00' },
  { value: 'evening', label: '夕方', period: '17:00-19:00' },
  { value: 'custom', label: '時間指定', period: '具体的な時間' }
]

// 準備事項
const preparationItems = [
  { id: 'measurement_tools', label: '計測器具' },
  { id: 'sample_materials', label: '材料サンプル' },
  { id: 'estimate_sheet', label: '見積書' },
  { id: 'contract_documents', label: '契約書類' },
  { id: 'company_brochure', label: '会社パンフレット' },
  { id: 'reference_photos', label: '施工事例写真' },
  { id: 'safety_equipment', label: '安全装備' },
  { id: 'tablet_laptop', label: 'タブレット・PC' }
]

// AI提案
const aiSuggestion = computed(() => {
  if (!props.case) return null
  
  const suggestions = {
    '外壁塗装': {
      message: '外壁塗装の現地調査では、外壁の状態、築年数、周辺環境を詳しく確認してください。',
      checkPoints: [
        '外壁材の種類と劣化状況の確認',
        '前回塗装時期と使用塗料の聞き取り',
        '雨漏りやひび割れの有無',
        '足場設置の可否と周辺環境',
        'カラーの希望と近隣への配慮'
      ]
    },
    '屋根修繕': {
      message: '屋根の緊急修繕の場合は、安全確保を最優先に迅速な対応を心がけてください。',
      checkPoints: [
        '雨漏りの箇所と被害範囲の確認',
        '屋根材の種類と損傷状況',
        '応急処置の必要性',
        '本格修繕の工期と費用',
        '保険適用の可能性'
      ]
    }
  }
  
  const workType = Object.keys(suggestions).find(type => 
    props.case?.title?.includes(type)
  )
  
  return suggestions[workType] || {
    message: 'お客様のニーズを丁寧にヒアリングし、最適な提案を心がけてください。',
    checkPoints: [
      'お客様の具体的な要望の確認',
      '予算と工期の相談',
      '施工方法の説明',
      '今後のスケジュール調整'
    ]
  }
})

// 最小日付（今日以降）
const minDate = computed(() => {
  const today = new Date()
  return today.toISOString().split('T')[0]
})

// フォームの有効性
const isFormValid = computed(() => {
  return selectedVisitType.value && 
         visitDate.value && 
         (selectedTimeSlot.value !== 'custom' || customTime.value)
})

// メソッド
const closeModal = () => {
  resetModal()
  emit('close')
}

const resetModal = () => {
  selectedVisitType.value = null
  visitDate.value = ''
  selectedTimeSlot.value = null
  customTime.value = ''
  visitDuration.value = '60'
  customDuration.value = ''
  selectedPreparations.value = []
  visitMemo.value = ''
  reminder.value = {
    enabled: true,
    before: 30,
    methods: {
      push: true,
      email: false,
      sms: false
    }
  }
}

const copyToClipboard = async (text) => {
  try {
    await navigator.clipboard.writeText(text)
    alert('電話番号をコピーしました')
  } catch (err) {
    console.error('コピーに失敗:', err)
  }
}

const openMap = () => {
  const address = encodeURIComponent(props.case?.location || '')
  const mapUrl = `https://www.google.com/maps/search/?api=1&query=${address}`
  window.open(mapUrl, '_blank')
}

const selectVisitType = (type) => {
  selectedVisitType.value = type
}

const selectTimeSlot = (slot) => {
  selectedTimeSlot.value = slot
  if (slot.value !== 'custom') {
    customTime.value = ''
  }
}

const scheduleVisit = async () => {
  isScheduling.value = true
  
  try {
    // 訪問時間の計算
    let visitTime = ''
    if (selectedTimeSlot.value.value === 'custom') {
      visitTime = customTime.value
    } else {
      // デフォルト時間を設定
      const defaultTimes = {
        'morning': '10:00',
        'afternoon': '14:00',
        'evening': '17:30'
      }
      visitTime = defaultTimes[selectedTimeSlot.value.value]
    }
    
    const visitDateTime = new Date(`${visitDate.value}T${visitTime}`)
    
    const visitData = {
      caseId: props.case?.id,
      type: selectedVisitType.value.id,
      typeLabel: selectedVisitType.value.label,
      scheduledAt: visitDateTime.toISOString(),
      duration: visitDuration.value === 'custom' ? customDuration.value : visitDuration.value,
      preparations: selectedPreparations.value,
      memo: visitMemo.value,
      reminder: reminder.value,
      customerInfo: {
        name: props.case?.customerName,
        location: props.case?.location,
        phoneNumber: props.case?.phoneNumber
      },
      timestamp: new Date().toISOString()
    }
    
    // 訪問予定保存API呼び出し（実装予定）
    console.log('訪問予定保存:', visitData)
    
    // 成功メッセージ
    alert('✅ 訪問予定を設定しました！')
    
    // 親コンポーネントに完了を通知
    emit('visit-scheduled', visitData)
    
    closeModal()
  } catch (error) {
    console.error('訪問予定設定エラー:', error)
    alert('❌ 訪問予定の設定に失敗しました')
  } finally {
    isScheduling.value = false
  }
}

// ウォッチャー
watch(() => props.show, (newValue) => {
  if (newValue) {
    resetModal()
    // デフォルト値を設定
    const tomorrow = new Date()
    tomorrow.setDate(tomorrow.getDate() + 1)
    visitDate.value = tomorrow.toISOString().split('T')[0]
    
    // デフォルトで現地調査を選択
    selectedVisitType.value = visitTypes[0]
    selectedTimeSlot.value = timeSlots[0] // 午前中
  }
})

// ライフサイクル
onMounted(() => {
  // 初期化処理（必要に応じて）
})
</script>

