  <div class="ai-advisor" :class="{ 'expanded': isExpanded, 'minimized': isMinimized }">
    <!-- アドバイザーヘッダー -->
    <div class="advisor-header" @click="toggleExpansion">
      <div class="advisor-icon">
        <span class="ai-avatar">🤖</span>
        <div v-if="isThinking" class="thinking-indicator">
          <div class="thinking-dots">
            <span></span>
            <span></span>
            <span></span>
          </div>
        </div>
      </div>
      
      <div class="advisor-info" v-if="!isMinimized">
        <h4 class="advisor-title">AIアシスタント</h4>
        <p class="advisor-status">{{ currentStatus }}</p>
      </div>
      
      <div class="advisor-controls">
        <button v-if="notifications.length > 0" @click.stop="showNotifications = !showNotifications" class="notification-btn">
          <span class="notification-count">{{ notifications.length }}</span>
          🔔
        </button>
        <button @click.stop="toggleMinimize" class="minimize-btn">
          {{ isMinimized ? '📖' : '📘' }}
        </button>
      </div>
    </div>
    
    <!-- 通知リスト -->
    <div v-if="showNotifications && !isMinimized" class="notifications-panel">
      <h5>🔔 AI通知</h5>
      <div class="notifications-list">
        <div 
          v-for="notification in notifications" 
          :key="notification.id"
          class="notification-item"
          :class="notification.type"
        >
          <div class="notification-icon">{{ getNotificationIcon(notification.type) }}</div>
          <div class="notification-content">
            <p class="notification-message">{{ notification.message }}</p>
            <span class="notification-time">{{ formatTime(notification.timestamp) }}</span>
          </div>
          <button @click="dismissNotification(notification.id)" class="dismiss-btn">✕</button>
        </div>
      </div>
    </div>
    
    <!-- メインコンテンツ -->
    <div v-if="isExpanded && !isMinimized" class="advisor-content">
      <!-- 現在の提案 -->
      <div v-if="currentSuggestion" class="current-suggestion">
        <div class="suggestion-header">
          <span class="suggestion-icon">💡</span>
          <h5>{{ currentSuggestion.title }}</h5>
          <span class="suggestion-priority" :class="currentSuggestion.priority">
            {{ getPriorityLabel(currentSuggestion.priority) }}
          </span>
        </div>
        
        <p class="suggestion-message">{{ currentSuggestion.message }}</p>
        
        <div v-if="currentSuggestion.actions" class="suggestion-actions">
          <button 
            v-for="action in currentSuggestion.actions"
            :key="action.id"
            @click="executeAction(action)"
            class="suggestion-action-btn"
            :class="action.type"
          >
            <span class="action-icon">{{ action.icon }}</span>
            {{ action.label }}
          </button>
        </div>
        
        <div class="suggestion-footer">
          <button @click="dismissSuggestion" class="dismiss-suggestion">後で</button>
          <button @click="markAsUseful" class="mark-useful">👍 役立った</button>
        </div>
      </div>
      
      <!-- AIチャット -->
      <div class="ai-chat">
        <div class="chat-header">
          <span>💬 AIに質問</span>
          <button @click="clearChat" class="clear-chat">🗑️</button>
        </div>
        
        <div class="chat-messages" ref="chatMessages">
          <div 
            v-for="message in chatHistory" 
            :key="message.id"
            class="chat-message"
            :class="message.type"
          >
            <div class="message-content">
              <p>{{ message.text }}</p>
              <span class="message-time">{{ formatTime(message.timestamp) }}</span>
            </div>
          </div>
        </div>
        
        <div class="chat-input">
          <div class="quick-questions">
            <button 
              v-for="question in quickQuestions"
              :key="question.id"
              @click="askQuickQuestion(question)"
              class="quick-question-btn"
              :disabled="isThinking"
            >
              {{ question.text }}
            </button>
          </div>
          
          <div class="input-area">
            <input 
              v-model="chatInput"
              @keydown.enter="sendMessage"
              placeholder="AIに質問してください..."
              class="chat-input-field"
              :disabled="isThinking"
            />
            <button 
              @click="sendMessage" 
              class="send-btn"
              :disabled="!chatInput.trim() || isThinking"
            >
              <span v-if="isThinking" class="loading-spinner"></span>
              <span v-else>📤</span>
            </button>
          </div>
        </div>
      </div>
      
      <!-- 学習データ -->
      <div class="learning-insights">
        <h5>📊 学習データ</h5>
        <div class="insights-grid">
          <div class="insight-item">
            <span class="insight-label">成功パターン</span>
            <span class="insight-value">{{ learningData.successPatterns }}</span>
          </div>
          <div class="insight-item">
            <span class="insight-label">推奨時間帯</span>
            <span class="insight-value">{{ learningData.bestTimeSlot }}</span>
          </div>
          <div class="insight-item">
            <span class="insight-label">平均成約率</span>
            <span class="insight-value">{{ learningData.avgConversionRate }}%</span>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch, nextTick, onMounted, onUnmounted } from 'vue'

const props = defineProps({
  currentCase: Object,
  recentActions: Array,
  schedule: Array,
  performance: Object
})

const emit = defineEmits(['execute-suggestion', 'request-action'])

// リアクティブデータ
const isExpanded = ref(false)
const isMinimized = ref(false)
const isThinking = ref(false)
const showNotifications = ref(false)
const chatInput = ref('')
const chatHistory = ref([])
const notifications = ref([])
const currentSuggestion = ref(null)

// 学習データ（モック）
const learningData = ref({
  successPatterns: '午前中の電話',
  bestTimeSlot: '10:00-11:00',
  avgConversionRate: 23
})

// クイック質問
const quickQuestions = [
  { id: 1, text: '次に何をすべき？' },
  { id: 2, text: 'この案件の優先度は？' },
  { id: 3, text: '成功の秘訣は？' },
  { id: 4, text: '時間配分のアドバイス' }
]

// 計算プロパティ
const currentStatus = computed(() => {
  if (isThinking.value) return 'AI思考中...'
  if (notifications.value.length > 0) return `${notifications.value.length}件の提案あり`
  if (currentSuggestion.value) return '新しい提案があります'
  return 'AI待機中'
})

// メソッド
const toggleExpansion = () => {
  if (!isMinimized.value) {
    isExpanded.value = !isExpanded.value
  }
}

const toggleMinimize = () => {
  isMinimized.value = !isMinimized.value
  if (isMinimized.value) {
    isExpanded.value = false
    showNotifications.value = false
  }
}

const getNotificationIcon = (type) => {
  const icons = {
    urgent: '🚨',
    suggestion: '💡',
    warning: '⚠️',
    info: 'ℹ️',
    success: '✅'
  }
  return icons[type] || '📢'
}

const getPriorityLabel = (priority) => {
  const labels = {
    high: '高',
    medium: '中',
    low: '低'
  }
  return labels[priority] || priority
}

const formatTime = (timestamp) => {
  return new Date(timestamp).toLocaleTimeString('ja-JP', { 
    hour: '2-digit', 
    minute: '2-digit' 
  })
}

const dismissNotification = (id) => {
  notifications.value = notifications.value.filter(n => n.id !== id)
}

const executeAction = (action) => {
  emit('execute-suggestion', action)
  
  // 提案を実行済みにマーク
  if (currentSuggestion.value) {
    addChatMessage('ai', `「${action.label}」を実行しました。結果をお聞かせください。`)
  }
}

const dismissSuggestion = () => {
  currentSuggestion.value = null
}

const markAsUseful = () => {
  addChatMessage('ai', 'フィードバックありがとうございます！学習データに反映します。')
  currentSuggestion.value = null
}

const clearChat = () => {
  chatHistory.value = []
}

const askQuickQuestion = async (question) => {
  chatInput.value = question.text
  await sendMessage()
}

const sendMessage = async () => {
  if (!chatInput.value.trim() || isThinking.value) return
  
  const userMessage = chatInput.value
  chatInput.value = ''
  
  // ユーザーメッセージを追加
  addChatMessage('user', userMessage)
  
  // AI応答を生成
  isThinking.value = true
  
  try {
    await new Promise(resolve => setTimeout(resolve, 1500)) // モック遅延
    
    const aiResponse = generateAIResponse(userMessage)
    addChatMessage('ai', aiResponse)
  } finally {
    isThinking.value = false
  }
}

const addChatMessage = (type, text) => {
  const message = {
    id: Date.now(),
    type,
    text,
    timestamp: new Date().toISOString()
  }
  
  chatHistory.value.push(message)
  
  // 自動スクロール
  nextTick(() => {
    const chatMessages = document.querySelector('.chat-messages')
    if (chatMessages) {
      chatMessages.scrollTop = chatMessages.scrollHeight
    }
  })
}

const generateAIResponse = (userMessage) => {
  // モックAI応答生成
  const responses = {
    '次に何をすべき？': '現在の案件状況から、山田様への電話フォローアップが最優先です。前回の見積もりから3日経過しており、お客様からの反応を確認すべきタイミングです。',
    'この案件の優先度は？': '緊急度：高　理由：築30年で初回塗装のため、劣化が進行している可能性があります。早期対応で信頼獲得につながります。',
    '成功の秘訣は？': 'お客様の立場に立った丁寧な説明が重要です。特に「なぜ今なのか」を具体的な劣化状況と共に説明することで、緊急性を理解していただけます。',
    '時間配分のアドバイス': '午前中（10-11時）の電話が最も効果的です。お客様の在宅率が高く、落ち着いて話を聞いていただけます。訪問は14-16時がおすすめです。'
  }
  
  // 部分一致で応答を検索
  for (const [key, response] of Object.entries(responses)) {
    if (userMessage.includes(key.slice(0, 3))) {
      return response
    }
  }
  
  // デフォルト応答
  return `「${userMessage}」について分析中です。具体的な状況をお聞かせいただければ、より詳細なアドバイスを提供できます。`
}

const addNotification = (type, message) => {
  const notification = {
    id: Date.now(),
    type,
    message,
    timestamp: new Date().toISOString()
  }
  
  notifications.value.unshift(notification)
  
  // 通知数制限
  if (notifications.value.length > 5) {
    notifications.value = notifications.value.slice(0, 5)
  }
}

const generateSuggestion = () => {
  // 現在の状況に基づいて提案を生成
  const suggestions = [
    {
      id: 1,
      title: '最適なタイミング',
      message: '山田様への電話は今が最適です。前回のやり取りから適切な間隔が空いており、フォローアップに最良のタイミングです。',
      priority: 'high',
      actions: [
        { id: 'call', type: 'primary', icon: '📞', label: '今すぐ電話' },
        { id: 'schedule', type: 'secondary', icon: '📅', label: '30分後に予約' }
      ]
    },
    {
      id: 2,
      title: '資料準備の提案',
      message: '佐藤様の訪問前に、近隣の施工事例写真を準備することをお勧めします。類似物件の実績が成約率を20%向上させます。',
      priority: 'medium',
      actions: [
        { id: 'prepare', type: 'primary', icon: '📋', label: '資料準備' },
        { id: 'remind', type: 'secondary', icon: '⏰', label: 'リマインダー設定' }
      ]
    }
  ]
  
  // ランダムまたは条件に基づいて提案を選択
  currentSuggestion.value = suggestions[Math.floor(Math.random() * suggestions.length)]
}

// 自動AI分析
const analyzeCurrentSituation = () => {
  // 定期的に状況を分析し、提案やアラートを生成
  const now = new Date()
  const hour = now.getHours()
  
  // 時間帯に基づく提案
  if (hour >= 10 && hour <= 11 && Math.random() > 0.7) {
    generateSuggestion()
  }
  
  // ランダムな通知生成（デモ用）
  if (Math.random() > 0.8) {
    const notificationTypes = [
      { type: 'suggestion', message: '新しい案件に最適なアプローチ方法を発見しました' },
      { type: 'warning', message: '高橋様の案件が3日間フォローされていません' },
      { type: 'info', message: '今月の成約率が先月より15%向上しています' }
    ]
    
    const randomNotification = notificationTypes[Math.floor(Math.random() * notificationTypes.length)]
    addNotification(randomNotification.type, randomNotification.message)
  }
}

// ライフサイクル
let analysisInterval = null

onMounted(() => {
  // 初期メッセージ
  addChatMessage('ai', 'こんにちは！営業活動をサポートします。何かご質問はありますか？')
  
  // 定期分析開始
  analysisInterval = setInterval(analyzeCurrentSituation, 30000) // 30秒ごと
  
  // 初回提案生成
  setTimeout(generateSuggestion, 5000)
})

onUnmounted(() => {
  if (analysisInterval) {
    clearInterval(analysisInterval)
  }
})

// ウォッチャー
watch(() => props.currentCase, (newCase) => {
  if (newCase) {
    addChatMessage('ai', `${newCase.customerName}様の案件について分析します。何かお手伝いできることはありますか？`)
  }
})

watch(() => props.recentActions, (newActions) => {
  if (newActions && newActions.length > 0) {
    const lastAction = newActions[newActions.length - 1]
    addNotification('success', `${lastAction.type}アクションが完了しました。次のステップを分析中です。`)
  }
})
</script>

