<script setup>
import { ref, computed, onMounted, watch } from 'vue'
import { actionLogger } from '@/services/actionLogger.js'

const props = defineProps({
  visible: {
    type: Boolean,
    default: true
  }
})

// リアクティブデータ
const selectedPeriod = ref(7)
const isLoading = ref(false)
const showDetailedData = ref(false)
const analysisData = ref(null)
const recentLogs = ref([])

// 計算プロパティ
const overview = computed(() => {
  if (!analysisData.value) return {
    totalActions: 0,
    successRate: 0,
    avgActionsPerDay: 0,
    mostActiveHour: null
  }
  return analysisData.value.overview
})

const trends = computed(() => {
  // 前期間との比較計算（簡略版）
  return {
    actionTrend: Math.random() * 20 - 10, // -10 to +10
    successTrend: Math.random() * 10 - 5, // -5 to +5
    productivityTrend: Math.random() * 15 - 7.5 // -7.5 to +7.5
  }
})

const dailyTrendData = computed(() => {
  if (!analysisData.value?.trends?.weeklyTrend) return []
  
  // 簡単な日次データ生成（実際は actionLogger から取得）
  const days = []
  for (let i = selectedPeriod.value - 1; i >= 0; i--) {
    const date = new Date(Date.now() - i * 24 * 60 * 60 * 1000)
    days.push({
      date: date.toISOString().split('T')[0],
      actions: Math.floor(Math.random() * 10) + 1,
      successRate: Math.random() * 40 + 60
    })
  }
  return days
})

const maxDailyActions = computed(() => {
  return Math.max(...dailyTrendData.value.map(d => d.actions), 1)
})

const actionTypeData = computed(() => {
  if (!analysisData.value?.trends?.actionTypeTrend) return []
  return analysisData.value.trends.actionTypeTrend.slice(0, 5)
})

const insights = computed(() => {
  return analysisData.value?.insights || []
})

const recommendations = computed(() => {
  return analysisData.value?.recommendations || []
})

// メソッド
const loadData = async () => {
  isLoading.value = true
  try {
    // パフォーマンス分析データを取得
    analysisData.value = actionLogger.getPerformanceAnalysis()
    recentLogs.value = actionLogger.getRecentLogs(selectedPeriod.value)
  } catch (error) {
    console.error('パフォーマンスデータの読み込みエラー:', error)
  } finally {
    isLoading.value = false
  }
}

const updatePeriod = () => {
  loadData()
}

const refreshData = () => {
  loadData()
}

const exportData = () => {
  try {
    const exportData = actionLogger.exportData('json')
    const blob = new Blob([exportData], { type: 'application/json' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `performance_data_${new Date().toISOString().split('T')[0]}.json`
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)
    URL.revokeObjectURL(url)
  } catch (error) {
    console.error('エクスポートエラー:', error)
    alert('データのエクスポートに失敗しました')
  }
}

const getBestHourPerformance = () => {
  const bestHours = analysisData.value?.overview?.bestPerformingHours || []
  return bestHours.length > 0 ? (bestHours[0].successRate * 100).toFixed(0) : '--'
}

const getSuccessRateColor = (rate) => {
  if (rate >= 80) return '#10b981'
  if (rate >= 60) return '#f59e0b'
  return '#ef4444'
}

const getActionIcon = (actionType) => {
  const icons = {
    call: '📞',
    sms: '💬',
    visit: '🏠',
    email: '📧',
    meeting: '💼'
  }
  return icons[actionType] || '📋'
}

const getActionLabel = (actionType) => {
  const labels = {
    call: '電話',
    sms: 'SMS',
    visit: '訪問',
    email: 'メール',
    meeting: '会議'
  }
  return labels[actionType] || actionType
}

const getActionColor = (actionType) => {
  const colors = {
    call: '#3b82f6',
    sms: '#10b981',
    visit: '#f59e0b',
    email: '#8b5cf6',
    meeting: '#ef4444'
  }
  return colors[actionType] || '#6b7280'
}

const getHourStats = (hour) => {
  // 実際の時間帯別統計（簡略版）
  return {
    actions: Math.floor(Math.random() * 5),
    successRate: Math.random() * 40 + 50
  }
}

const getHourCellClass = (hour) => {
  const stats = getHourStats(hour)
  if (stats.actions === 0) return 'no-activity'
  if (stats.successRate >= 80) return 'high-performance'
  if (stats.successRate >= 60) return 'medium-performance'
  return 'low-performance'
}

const getInsightIcon = (type) => {
  const icons = {
    positive: '🎉',
    warning: '⚠️',
    info: 'ℹ️',
    suggestion: '💡'
  }
  return icons[type] || '📊'
}

const getPriorityLabel = (priority) => {
  const labels = {
    high: '高',
    medium: '中',
    low: '低'
  }
  return labels[priority] || priority
}

const getOutcomeClass = (outcome) => {
  if (actionLogger.isSuccessOutcome(outcome)) return 'success'
  if (actionLogger.isFailureOutcome(outcome)) return 'failure'
  return 'neutral'
}

const getOutcomeLabel = (outcome) => {
  const labels = {
    answered_positive: '好反応',
    answered_negative: '否定的',
    no_answer: '不在',
    success: '成功',
    failed: '失敗',
    completed: '完了'
  }
  return labels[outcome] || outcome
}

const formatDateLabel = (dateString) => {
  const date = new Date(dateString)
  return `${date.getMonth() + 1}/${date.getDate()}`
}

const formatDateTime = (timestamp) => {
  return new Date(timestamp).toLocaleString('ja-JP', {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  })
}

const formatDuration = (duration) => {
  if (!duration) return '-'
  const minutes = Math.floor(duration / 60)
  const seconds = duration % 60
  return `${minutes}:${seconds.toString().padStart(2, '0')}`
}

// ライフサイクル
onMounted(() => {
  loadData()
})

watch(() => props.visible, (newValue) => {
  if (newValue) {
    loadData()
  }
})
</script>

