<script setup>
import { ref, computed, onMounted, watch } from 'vue'
import { useAuthStore } from '@/stores/auth'
import { useInquiriesStore } from '@/stores/inquiries'
import AppLayout from '@/components/Layout/AppLayout.vue'
import SkeletonLoader from '@/components/Common/SkeletonLoader.vue'
import ChatHistoryModal from '@/components/Modal/ChatHistoryModal.vue'

// Stores
const authStore = useAuthStore()
const inquiriesStore = useInquiriesStore()

// Local state
const searchText = ref('')
const showInquiryModal = ref(false)
const selectedInquiry = ref(null)
const showChatModal = ref(false)
const selectedChatInquiry = ref(null)
const responseForm = ref({
  message: '',
  scheduledDate: '',
  estimatedAmount: ''
})

// Computed
const filteredInquiries = computed(() => {
  return inquiriesStore.filteredInquiries
})

const loading = computed(() => {
  return inquiriesStore.loading
})

const error = computed(() => {
  return inquiriesStore.error
})

const statusCounts = computed(() => {
  return inquiriesStore.statusCounts
})

// Methods
const getStatusLabel = (status) => {
  return inquiriesStore.getStatusLabel(status)
}

const getPriorityLabel = (priority) => {
  return inquiriesStore.getPriorityLabel(priority)
}

const formatDate = (dateString) => {
  if (!dateString) return ''
  const date = new Date(dateString)
  return date.toLocaleDateString('ja-JP', {
    month: 'numeric',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  })
}

const selectInquiry = (inquiry) => {
  selectedInquiry.value = inquiry
  showInquiryModal.value = true
}

const respondToInquiry = async (inquiry) => {
  try {
    const success = await inquiriesStore.respondToInquiry(inquiry.id, responseForm.value)
    if (success) {
      responseForm.value = {
        message: '',
        scheduledDate: '',
        estimatedAmount: ''
      }
      showInquiryModal.value = false
      alert('案件対応を開始しました')
    }
  } catch (err) {
    console.error('Error responding to inquiry:', err)
  }
}

const createQuote = async (inquiry) => {
  try {
    const quoteData = {
      amount: responseForm.value.estimatedAmount,
      validUntil: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
      notes: responseForm.value.message
    }
    
    const success = await inquiriesStore.createQuote(inquiry.id, quoteData)
    if (success) {
      showInquiryModal.value = false
      alert('見積を作成しました')
    }
  } catch (err) {
    console.error('Error creating quote:', err)
  }
}

const viewDetails = (inquiry) => {
  selectedInquiry.value = inquiry
  showInquiryModal.value = true
}

const refreshInquiries = async () => {
  const childId = authStore.user?.childId
  if (childId) {
    await inquiriesStore.fetchInquiries(childId)
  }
}

// タグ関連メソッド
const getDisplayTags = (tags) => {
  if (!tags || !Array.isArray(tags)) return []
  return tags.slice(0, 3)
}

const getHiddenTagsText = (tags) => {
  if (!tags || tags.length <= 3) return ''
  const hiddenTags = tags.slice(3)
  return hiddenTags.map(tag => tag.name || tag).join(', ')
}

// チャット履歴関連メソッド
const openChatHistory = (inquiry) => {
  selectedChatInquiry.value = inquiry
  showChatModal.value = true
}

const closeChatModal = () => {
  showChatModal.value = false
  selectedChatInquiry.value = null
}

const setStatusFilter = (status) => {
  inquiriesStore.setFilters({ status })
}

const setPeriodFilter = (period) => {
  inquiriesStore.setFilters({ period })
}

const clearError = () => {
  inquiriesStore.clearError()
}

const closeModal = () => {
  showInquiryModal.value = false
  selectedInquiry.value = null
  responseForm.value = {
    message: '',
    scheduledDate: '',
    estimatedAmount: ''
  }
}

// Watch for search text changes
watch(searchText, (newValue) => {
  inquiriesStore.setFilters({ searchText: newValue })
})

// Initial load
onMounted(() => {
  refreshInquiries()
})
</script>

