          <h3>💬 SMS送信</h3>
          <p class="customer-info">{{ case_?.customerName || '未設定' }}様 - {{ case_?.title || '案件名未設定' }}</p>
        </div>
        <button @click="closeModal" class="modal-close">✕</button>
      </div>

      <!-- お客様情報 -->
      <div class="customer-details">
        <div class="detail-row">
          <span class="detail-label">📱 電話番号</span>
          <span class="detail-value">{{ case_.phoneNumber }}</span>
          <button @click="copyToClipboard(case_.phoneNumber)" class="copy-btn" title="コピー">
            📋
          </button>
        </div>
        <div class="detail-row">
          <span class="detail-label">📍 住所</span>
          <span class="detail-value">{{ case_.location }}</span>
        </div>
      </div>

      <!-- AI提案 -->
      <div v-if="aiSuggestion" class="ai-suggestion">
        <div class="ai-icon">🤖</div>
        <div class="ai-content">
          <h4>AI SMS提案</h4>
          <p>{{ aiSuggestion.message }}</p>
        </div>
      </div>

      <!-- テンプレート選択 -->
      <div class="template-section">
        <h4>📝 テンプレート選択</h4>
        <div class="template-categories">
          <button 
            v-for="category in templateCategories"
            :key="category.id"
            @click="selectCategory(category)"
            class="category-btn"
            :class="{ active: selectedCategory?.id === category.id }"
          >
            <span class="category-icon">{{ category.icon }}</span>
            <span class="category-label">{{ category.label }}</span>
          </button>
        </div>

        <div v-if="selectedCategory" class="template-list">
          <div 
            v-for="template in availableTemplates"
            :key="template.id"
            @click="selectTemplate(template)"
            class="template-item"
            :class="{ active: selectedTemplate?.id === template.id }"
          >
            <div class="template-header">
              <h5>{{ template.title }}</h5>
              <span class="template-length">{{ template.text.length }}文字</span>
            </div>
            <p class="template-preview">{{ template.text }}</p>
