          <div class="character-count" :class="{ warning: smsText.length > 70, danger: smsText.length > 140 }">
            {{ smsText.length }}/140文字
          </div>
        </div>
        
        <textarea 
          v-model="smsText"
          class="sms-textarea"
          placeholder="SMS内容を入力してください..."
          maxlength="140"
          rows="6"
        ></textarea>
        
        <div class="editor-tools">
          <button @click="insertCustomerName" class="tool-btn">
            👤 お客様名
          </button>
          <button @click="insertCompanyName" class="tool-btn">
            🏢 会社名
          </button>
          <button @click="insertPhoneNumber" class="tool-btn">
            📞 連絡先
          </button>
          <button @click="improveWithAI" class="tool-btn ai-btn" :disabled="isImproving">
            <span v-if="isImproving" class="loading-spinner"></span>
            🤖 AI改善
          </button>
        </div>
      </div>

      <!-- プレビュー -->
      <div class="sms-preview">
        <h4>📱 送信プレビュー</h4>
        <div class="phone-preview">
          <div class="phone-screen">
            <div class="message-bubble outgoing">
              <p>{{ smsText || 'SMS内容を入力してください...' }}</p>
              <div class="message-time">{{ currentTime }}</div>
            </div>
          </div>
        </div>
      </div>

      <!-- 送信設定 -->
      <div class="send-options">
        <div class="timing-options">
          <h5>⏰ 送信タイミング</h5>
          <label class="radio-option">
            <input type="radio" v-model="sendTiming" value="now" />
            <span>今すぐ送信</span>
          </label>
          <label class="radio-option">
            <input type="radio" v-model="sendTiming" value="scheduled" />
            <span>予約送信</span>
          </label>
          
          <div v-if="sendTiming === 'scheduled'" class="schedule-inputs">
            <input 
              type="datetime-local" 
              v-model="scheduledTime"
              class="schedule-input"
              :min="minScheduleTime"
            />
          </div>
        </div>
      </div>

      <!-- アクションボタン -->
      <div class="action-buttons">
        <button @click="closeModal" class="btn btn-outline">
          キャンセル
        </button>
        <button 
          @click="sendSMS" 
          class="btn btn-primary btn-lg"
          :disabled="!smsText.trim() || isSending"
        >
          <span v-if="isSending" class="loading-spinner"></span>
          <span v-else class="btn-icon">💬</span>
          {{ sendTiming === 'now' ? 'SMS送信' : '予約設定' }}
        </button>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch, onMounted } from 'vue'

const props = defineProps({
  show: Boolean,
  case: Object
})

const emit = defineEmits(['close', 'sms-sent'])

// リアクティブデータ
const selectedCategory = ref(null)
const selectedTemplate = ref(null)
const smsText = ref('')
const sendTiming = ref('now')
const scheduledTime = ref('')
const isSending = ref(false)
const isImproving = ref(false)
const currentTime = ref('')

// テンプレートカテゴリ
const templateCategories = [
  { id: 'greeting', icon: '👋', label: '初回挨拶' },
  { id: 'followup', icon: '📞', label: 'フォローアップ' },
  { id: 'appointment', icon: '📅', label: 'アポイント' },
  { id: 'info', icon: '📋', label: '情報提供' },
  { id: 'thanks', icon: '🙏', label: 'お礼' }
]

// テンプレート一覧
const templates = {
  greeting: [
    {
      id: 'greeting_1',
      title: '初回ご挨拶',
      text: 'はじめまして。外壁塗装について、お気軽にご相談ください。無料で現地調査も承ります。【{会社名}】'
    },
    {
      id: 'greeting_2',
      title: 'お問い合わせお礼',
      text: 'この度はお問い合わせいただき、ありがとうございます。{お客様名}様のご希望をお聞かせください。【{会社名}】'
    }
  ],
  followup: [
    {
      id: 'followup_1',
      title: '電話不在フォロー',
      text: '先ほどお電話いたしましたが、ご不在でした。ご都合の良いお時間をお聞かせください。【{会社名}】'
    },
    {
      id: 'followup_2',
      title: '検討状況確認',
      text: '{お客様名}様、外壁塗装の件はいかがでしょうか。ご不明な点がございましたら、お気軽にお尋ねください。【{会社名}】'
    }
  ],
  appointment: [
    {
      id: 'appointment_1',
      title: '現地調査のお誘い',
      text: '無料の現地調査はいかがでしょうか。{お客様名}様のご都合に合わせて伺います。お気軽にご連絡ください。【{会社名}】'
    },
    {
      id: 'appointment_2',
      title: '打ち合わせ調整',
      text: 'お見積りの詳細についてご説明させていただきたく、お時間をいただけますでしょうか。【{会社名}】'
    }
  ],
  info: [
    {
      id: 'info_1',
      title: '工事実績紹介',
      text: '近隣での施工実績をご紹介いたします。写真付きの資料もご用意できます。ご興味があればお声かけください。【{会社名}】'
    },
    {
      id: 'info_2',
      title: '助成金情報',
      text: '外壁塗装の助成金制度についてご案内できます。お客様の地域で利用可能な制度をお調べいたします。【{会社名}】'
    }
  ],
  thanks: [
    {
      id: 'thanks_1',
      title: '契約お礼',
      text: '{お客様名}様、この度はご契約いただき、誠にありがとうございます。精一杯施工させていただきます。【{会社名}】'
    },
    {
      id: 'thanks_2',
      title: '完工お礼',
      text: '工事完了いたしました。{お客様名}様にご満足いただけるよう努めました。今後ともよろしくお願いいたします。【{会社名}】'
    }
  ]
}

// 計算プロパティ
const availableTemplates = computed(() => {
  return selectedCategory.value ? templates[selectedCategory.value.id] || [] : []
})

const aiSuggestion = computed(() => {
  if (!props.case) return null
  
  const timeOfDay = new Date().getHours()
  let timeAdvice = ''
  
  if (timeOfDay < 9) {
    timeAdvice = '朝早い時間なので、簡潔で礼儀正しい文面を心がけてください。'
  } else if (timeOfDay > 20) {
    timeAdvice = '夜遅い時間のため、緊急でない限り翌日の送信をお勧めします。'
  } else {
    timeAdvice = '営業時間内なので、積極的にコミュニケーションを図りましょう。'
  }
  
  return {
    message: `${props.case?.customerName || 'お客様'}への最初の印象が重要です。${timeAdvice}`
  }
})

const minScheduleTime = computed(() => {
  const now = new Date()
  const year = now.getFullYear()
  const month = String(now.getMonth() + 1).padStart(2, '0')
  const day = String(now.getDate()).padStart(2, '0')
  const hours = String(now.getHours()).padStart(2, '0')
  const minutes = String(now.getMinutes()).padStart(2, '0')
  
  return `${year}-${month}-${day}T${hours}:${minutes}`
})

// メソッド
const closeModal = () => {
  resetModal()
  emit('close')
}

const resetModal = () => {
  selectedCategory.value = null
  selectedTemplate.value = null
  smsText.value = ''
  sendTiming.value = 'now'
  scheduledTime.value = ''
}

const copyToClipboard = async (text) => {
  try {
    await navigator.clipboard.writeText(text)
    alert('電話番号をコピーしました')
  } catch (err) {
    console.error('コピーに失敗:', err)
  }
}

const selectCategory = (category) => {
  selectedCategory.value = category
  selectedTemplate.value = null
}

const selectTemplate = (template) => {
  selectedTemplate.value = template
  smsText.value = replacePlaceholders(template.text)
}

const replacePlaceholders = (text) => {
  return text
    .replace(/{お客様名}/g, props.case?.customerName || '[お客様名]')
    .replace(/{会社名}/g, '外壁リフォーム株式会社')
    .replace(/{連絡先}/g, props.case?.phoneNumber || '[連絡先]')
}

const insertCustomerName = () => {
  insertAtCursor(props.case?.customerName || '[お客様名]')
}

const insertCompanyName = () => {
  insertAtCursor('外壁リフォーム株式会社')
}

const insertPhoneNumber = () => {
  insertAtCursor('090-1234-5678')
}

const insertAtCursor = (text) => {
  const textarea = document.querySelector('.sms-textarea')
  const start = textarea.selectionStart
  const end = textarea.selectionEnd
  const before = smsText.value.substring(0, start)
  const after = smsText.value.substring(end)
  
  smsText.value = before + text + after
  
  // カーソル位置を調整
  setTimeout(() => {
    textarea.focus()
    textarea.setSelectionRange(start + text.length, start + text.length)
  }, 0)
}

const improveWithAI = async () => {
  if (!smsText.value.trim()) {
    alert('改善するテキストを入力してください')
    return
  }
  
  isImproving.value = true
  
  try {
    // AI改善ロジック（モック）
    await new Promise(resolve => setTimeout(resolve, 2000))
    
    const improvements = [
      '敬語表現をより丁寧に調整',
      '読みやすい文章構造に変更',
      '親しみやすい表現を追加',
      '行動を促す文言を強化'
    ]
    
    const randomImprovement = improvements[Math.floor(Math.random() * improvements.length)]
    smsText.value = smsText.value + `\n※${randomImprovement}しました`
    
    alert('🤖 AIによる改善が完了しました！')
  } catch (error) {
    console.error('AI改善エラー:', error)
    alert('❌ AI改善に失敗しました')
  } finally {
    isImproving.value = false
  }
}

const sendSMS = async () => {
  isSending.value = true
  
  try {
    const smsData = {
      caseId: props.case?.id,
      customerName: props.case?.customerName,
      phoneNumber: props.case?.phoneNumber,
      message: smsText.value,
      timing: sendTiming.value,
      scheduledAt: sendTiming.value === 'scheduled' ? scheduledTime.value : null,
      timestamp: new Date().toISOString()
    }
    
    // SMS送信API呼び出し（実装予定）
    console.log('SMS送信:', smsData)
    
    // 成功メッセージ
    if (sendTiming.value === 'now') {
      alert('✅ SMSを送信しました！')
    } else {
      alert('✅ SMS送信を予約しました！')
    }
    
    // 親コンポーネントに完了を通知
    emit('sms-sent', smsData)
    
    closeModal()
  } catch (error) {
    console.error('SMS送信エラー:', error)
    alert('❌ SMS送信に失敗しました')
  } finally {
    isSending.value = false
  }
}

const updateCurrentTime = () => {
  const now = new Date()
  currentTime.value = now.toLocaleTimeString('ja-JP', { 
    hour: '2-digit', 
    minute: '2-digit' 
  })
}

// ウォッチャー
watch(() => props.show, (newValue) => {
  if (newValue) {
    resetModal()
    updateCurrentTime()
  }
})

// ライフサイクル
onMounted(() => {
  updateCurrentTime()
  setInterval(updateCurrentTime, 60000) // 1分ごとに時刻を更新
})
</script>

