<!-- eslint-disable vue/multi-word-component-names -->
<template>
  <div class="login-page">
    <!-- ロール確認バッジ -->
    <div class="role-badge">
      🎯 営業支援システム | Role: {{ currentRole }}
    </div>
    
    <div class="login-container">
      <div class="login-header">
        <h1 class="login-title">外壁塗装くらべるAI</h1>
        <p class="login-subtitle">営業支援システム</p>
      </div>

      <form @submit.prevent="handleLogin" class="login-form">
        <div class="form-group">
          <label for="email" class="form-label">メールアドレス</label>
          <input
            id="email"
            type="email"
            v-model="loginForm.email"
            class="form-input"
            :class="{ 'error': errors.email }"
            placeholder="franchise@example.com"
            required
          >
          <span v-if="errors.email" class="error-message">{{ errors.email }}</span>
        </div>

        <div class="form-group">
          <label for="password" class="form-label">パスワード</label>
          <div class="password-input-container">
            <input
              id="password"
              :type="showPassword ? 'text' : 'password'"
              v-model="loginForm.password"
              class="form-input"
              :class="{ 'error': errors.password }"
              placeholder="パスワードを入力"
              required
            >
            <button
              type="button"
              class="password-toggle"
              @click="showPassword = !showPassword"
            >
              {{ showPassword ? '🙈' : '👁️' }}
            </button>
          </div>
          <span v-if="errors.password" class="error-message">{{ errors.password }}</span>
        </div>

        <div class="form-group">
          <label class="checkbox-label">
            <input
              type="checkbox"
              v-model="loginForm.rememberMe"
              class="checkbox-input"
            >
            <span class="checkbox-text">ログイン状態を保持する</span>
          </label>
        </div>

        <button
          type="submit"
          class="login-btn"
          :disabled="isLoading"
        >
          <span v-if="isLoading">ログイン中...</span>
          <span v-else>ログイン</span>
        </button>

        <div v-if="loginError" class="login-error">
          {{ loginError }}
        </div>
      </form>

      <div class="login-footer">
        <a href="#" class="forgot-password" @click.prevent="handleForgotPassword">
          パスワードを忘れた方はこちら
        </a>
      </div>

    </div>
  </div>
</template>

<script setup>
import { ref, reactive, onMounted, computed } from 'vue'
import { useRouter, useRoute } from 'vue-router'
import { useAuthStore } from '@/stores/auth'

// Router & Store
const router = useRouter()
const route = useRoute()
const authStore = useAuthStore()

// 現在のロール確認
const currentRole = computed(() => process.env.VUE_APP_ROLE || 'unknown')

// リアクティブデータ
const isLoading = ref(false)
const showPassword = ref(false)
const loginError = ref('')

const loginForm = reactive({
  email: '',
  password: '',
  rememberMe: false
})

const errors = reactive({
  email: '',
  password: ''
})

// バリデーション
const validateForm = () => {
  errors.email = ''
  errors.password = ''
  
  let isValid = true
  
  if (!loginForm.email) {
    errors.email = 'メールアドレスは必須です'
    isValid = false
  } else if (!isValidEmail(loginForm.email)) {
    errors.email = '有効なメールアドレスを入力してください'
    isValid = false
  }
  
  if (!loginForm.password) {
    errors.password = 'パスワードは必須です'
    isValid = false
  }
  
  return isValid
}

const isValidEmail = (email) => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
  return emailRegex.test(email)
}

// ログイン処理
const handleLogin = async () => {
  if (!validateForm()) {
    return
  }
  
  try {
    isLoading.value = true
    loginError.value = ''
    
    // 認証ストアを使用してログイン
    const result = await authStore.login({
      email: loginForm.email,
      password: loginForm.password
    })
    
    if (result.success) {
      // ログイン成功時の処理
      const redirectPath = route.query.redirect || '/dashboard'
      router.push(redirectPath)
    } else {
      loginError.value = result.error || 'ログインに失敗しました'
    }
    
  } catch (error) {
    console.error('Login error:', error)
    loginError.value = error.message || 'サーバーに接続できません'
  } finally {
    isLoading.value = false
  }
}

// パスワード忘れ
const handleForgotPassword = () => {
  alert('パスワードリセット機能は準備中です')
}

// ライフサイクル
onMounted(() => {
  console.log('🔧 [franchise-admin] Current Role:', currentRole.value)
  console.log('🔧 [franchise-admin] GAS WebApp URL:', process.env.VUE_APP_GAS_WEBAPP_URL)
  
  // 既にログイン済みの場合はリダイレクト
  if (localStorage.getItem('isAuthenticated') === 'true') {
    const redirectPath = route.query.redirect || '/dashboard'
    router.push(redirectPath)
  }
  
  // Remember Me の場合は情報を復元
  if (localStorage.getItem('rememberMe') === 'true') {
    const savedEmail = localStorage.getItem('userEmail')
    if (savedEmail) {
      loginForm.email = savedEmail
      loginForm.rememberMe = true
    }
  }
})
</script>

