<template>
  <div class="skeleton-loader" :class="[type, { animated: animated }]">
    <!-- テキスト行 -->
    <div v-if="type === 'text'" class="skeleton-text" :style="{ width: width, height: height }"></div>
    
    <!-- カードレイアウト -->
    <div v-else-if="type === 'card'" class="skeleton-card">
      <div class="skeleton-header">
        <div class="skeleton-avatar"></div>
        <div class="skeleton-title-group">
          <div class="skeleton-title"></div>
          <div class="skeleton-subtitle"></div>
        </div>
      </div>
      <div class="skeleton-content">
        <div class="skeleton-line" v-for="n in lines" :key="n"></div>
      </div>
    </div>
    
    <!-- テーブル行 -->
    <div v-else-if="type === 'table-row'" class="skeleton-table-row">
      <div v-for="n in columns" :key="n" class="skeleton-cell" :style="{ width: getCellWidth(n) }"></div>
    </div>
    
    <!-- テーブル全体 -->
    <div v-else-if="type === 'table'" class="skeleton-table">
      <div class="skeleton-table-header">
        <div v-for="n in columns" :key="n" class="skeleton-header-cell"></div>
      </div>
      <div v-for="r in rows" :key="r" class="skeleton-table-row">
        <div v-for="n in columns" :key="n" class="skeleton-cell"></div>
      </div>
    </div>
    
    <!-- リストアイテム -->
    <div v-else-if="type === 'list-item'" class="skeleton-list-item">
      <div class="skeleton-icon"></div>
      <div class="skeleton-content">
        <div class="skeleton-line primary"></div>
        <div class="skeleton-line secondary"></div>
      </div>
      <div class="skeleton-action"></div>
    </div>
    
    <!-- ダッシュボードメトリクス -->
    <div v-else-if="type === 'metric'" class="skeleton-metric">
      <div class="skeleton-metric-icon"></div>
      <div class="skeleton-metric-content">
        <div class="skeleton-metric-value"></div>
        <div class="skeleton-metric-label"></div>
        <div class="skeleton-metric-change"></div>
      </div>
    </div>
    
    <!-- カスタムレクタングル -->
    <div v-else class="skeleton-rectangle" :style="{ width: width, height: height }"></div>
  </div>
</template>

<script setup>
// Vue 3 Composition API
const props = defineProps({
  type: {
    type: String,
    default: 'text',
    validator: value => ['text', 'card', 'table', 'table-row', 'list-item', 'metric', 'rectangle'].includes(value)
  },
  width: {
    type: String,
    default: '100%'
  },
  height: {
    type: String,
    default: '20px'
  },
  lines: {
    type: Number,
    default: 3
  },
  rows: {
    type: Number,
    default: 5
  },
  columns: {
    type: Number,
    default: 4
  },
  animated: {
    type: Boolean,
    default: true
  }
})

const getCellWidth = (index) => {
  // テーブルセルの幅を動的に設定
  const widths = ['25%', '30%', '20%', '25%']
  return widths[index - 1] || '25%'
}
