// 計算プロパティ
const filteredCases = computed(() => {
  let filtered = cases.value

  if (caseFilter.value) {
    switch (caseFilter.value) {
      case 'urgent':
        filtered = filtered.filter(c => c.priority === 'high' || c.isUrgent)
        break
      case 'call_scheduled':
        filtered = filtered.filter(c => c.nextAction?.type === 'call')
        break
      case 'visit_scheduled':
        filtered = filtered.filter(c => c.nextAction?.type === 'visit')
        break
      case 'contract_ready':
        filtered = filtered.filter(c => c.status === 'quoted')
        break
      case 'stale':
        filtered = filtered.filter(c => {
          const lastAction = new Date(c.lastActionAt)
          const daysSince = (Date.now() - lastAction) / (1000 * 60 * 60 * 24)
          return daysSince > 3
        })
        break
    }
  }

  if (statusFilter.value) {
    filtered = filtered.filter(c => c.status === statusFilter.value)
  }

  return filtered
})

