const executeScheduleAction = (scheduleItem) => {
  console.log('スケジュールアクション実行:', scheduleItem)
  
  // アクションタイプに応じて適切なモーダルを開く
  switch (scheduleItem.type) {
    case 'call':
    case 'followup':
      // 電話アクション用の案件データを作成
      const callCase = {
        id: scheduleItem.id,
        customerName: scheduleItem.customer,
        title: scheduleItem.title,
        location: scheduleItem.location || '',
        phoneNumber: '090-1234-5678', // 実際のデータから取得
        notes: scheduleItem.notes
      }
      selectedCase.value = callCase
      showCallModal.value = true
      break
      
    case 'visit':
    case 'survey':
      // 訪問アクション用の案件データを作成
      const visitCase = {
        id: scheduleItem.id,
        customerName: scheduleItem.customer,
        title: scheduleItem.title,
        location: scheduleItem.location || '',
        phoneNumber: '090-1234-5678', // 実際のデータから取得
        notes: scheduleItem.notes
      }
      selectedCase.value = visitCase
      showVisitModal.value = true
      break
      
    default:
      // その他のアクションは直接完了とする
      markScheduleCompleted(scheduleItem)
      break
  }
}

