const handleCallCompleted = (logData) => {
  console.log('通話完了:', logData)
  // 案件データを更新
  const caseIndex = cases.value.findIndex(c => c.id === logData.caseId)
  if (caseIndex !== -1) {
    cases.value[caseIndex].lastActionAt = new Date().toISOString()
    
    // 次回アクションを設定
    if (logData.nextAction) {
      const nextActionTime = new Date(Date.now() + logData.nextAction.hours * 60 * 60 * 1000)
      cases.value[caseIndex].nextAction = {
        type: logData.nextAction.type,
        scheduledAt: nextActionTime.toISOString()
      }
      
      // 自動的に今日の予定に追加（今日中のアクションの場合）
      const today = new Date().toDateString()
      if (nextActionTime.toDateString() === today) {
        autoScheduleNextAction(logData.nextAction, cases.value[caseIndex], nextActionTime)
      }
    }
  }
  
  // アクションログシステムに記録
  actionLogger.logAction({
    caseId: logData.caseId,
    actionType: 'call',
    customerName: cases.value[caseIndex]?.customerName,
    outcome: logData.result,
    duration: logData.duration,
    memo: logData.memo,
    metadata: {
      nextAction: logData.nextAction
    }
  })
  
  // AI学習データに追加
  addActionToAIHistory('call', logData, cases.value[caseIndex])
  
  // 統計情報を更新
  stats.value.todayCalls++
}

const handleSMSSent = (smsData) => {
  console.log('SMS送信完了:', smsData)
  // 案件データを更新
  const caseIndex = cases.value.findIndex(c => c.id === smsData.caseId)
  if (caseIndex !== -1) {
    cases.value[caseIndex].lastActionAt = new Date().toISOString()
  }
  
  // アクションログシステムに記録
  actionLogger.logAction({
    caseId: smsData.caseId,
    actionType: 'sms',
    customerName: cases.value[caseIndex]?.customerName,
    outcome: 'completed',
    duration: 0,
    memo: smsData.message,
    metadata: {
      template: smsData.template,
      scheduled: smsData.scheduled
    }
  })
  
  // AI学習データに追加
  addActionToAIHistory('sms', smsData, cases.value[caseIndex])
}

const handleVisitScheduled = (visitData) => {
  console.log('訪問予定設定完了:', visitData)
  // 案件データを更新
  const caseIndex = cases.value.findIndex(c => c.id === visitData.caseId)
  if (caseIndex !== -1) {
    cases.value[caseIndex].lastActionAt = new Date().toISOString()
    cases.value[caseIndex].nextAction = {
      type: 'visit',
      scheduledAt: visitData.scheduledAt
    }
  }
  
  // アクションログシステムに記録
  actionLogger.logAction({
    caseId: visitData.caseId,
    actionType: 'visit',
    customerName: cases.value[caseIndex]?.customerName,
    outcome: 'scheduled',
    duration: visitData.duration || 60,
    memo: visitData.memo,
    metadata: {
      scheduledAt: visitData.scheduledAt,
      visitType: visitData.type,
      preparation: visitData.preparation
    }
  })
  
  // 今日の予定に自動追加
  const visitDate = new Date(visitData.scheduledAt)
  const today = new Date().toDateString()
  if (visitDate.toDateString() === today) {
    const newScheduleItem = {
      id: Date.now(),
      time: visitDate.toTimeString().slice(0, 5),
      duration: visitData.duration || 60,
      type: visitData.type || 'visit',
      title: visitData.typeLabel || '訪問予定',
      customer: visitData.customerInfo.name,
      location: visitData.customerInfo.location,
      notes: visitData.memo || '',
      urgent: false,
      completed: false
    }
    todaySchedule.value.push(newScheduleItem)
    
    // 時間順にソート
    todaySchedule.value.sort((a, b) => {
      return a.time.localeCompare(b.time)
    })
  }
  
  // AI学習データに追加
  addActionToAIHistory('visit', visitData, cases.value[caseIndex])
  
  // 統計情報を更新
  stats.value.scheduledVisits++
}

