    'visit': { icon: '🏠', label: '訪問予定' },
    'email': { icon: '📧', label: 'メール送信' },
    'sms': { icon: '💬', label: 'SMS送信' },
    'followup': { icon: '🔄', label: 'フォローアップ' }
  }
  
  const actionInfo = actionTypes[nextAction.type] || { icon: '📌', label: 'アクション' }
  
  const newScheduleItem = {
    id: Date.now(),
    time: scheduledTime.toTimeString().slice(0, 5),
    duration: 30, // デフォルト30分
    type: nextAction.type,
    title: actionInfo.label,
    customer: caseData.customerName,
    location: caseData.location || '',
    notes: `自動設定: ${nextAction.label || actionInfo.label}`,
    urgent: nextAction.type === 'call' && nextAction.hours <= 2, // 2時間以内の電話は緊急
    completed: false
  }
  
  todaySchedule.value.push(newScheduleItem)
  
  // 時間順にソート
  todaySchedule.value.sort((a, b) => {
    return a.time.localeCompare(b.time)
  })
  
  // 通知
  console.log(`自動スケジュール追加: ${newScheduleItem.time} ${newScheduleItem.title}`)
}

// AI関連メソッド
const addActionToAIHistory = (actionType, actionData, caseData) => {
  const actionRecord = {
    id: Date.now(),
    type: actionType,
    timestamp: new Date().toISOString(),
    caseId: caseData?.id,
    result: actionData.result || 'completed',
    data: actionData
  }
  
  recentActions.value.unshift(actionRecord)
  
  // 履歴サイズ制限
  if (recentActions.value.length > 50) {
    recentActions.value = recentActions.value.slice(0, 50)
  }
  
  // AIエンジンに学習データとして送信
  if (caseData) {
    aiEngine.learnFromAction({
      caseData: caseData,
      actionType: actionType,
      result: actionData.result || 'completed',
      timing: actionRecord.timestamp,
      duration: actionData.duration || 30
    })
  }
  
  // AIコンテキストを更新
  updateAIContext()
}

const updateAIContext = () => {
  const currentCase = selectedCase.value || (cases.value.length > 0 ? cases.value[0] : null)
  
  if (currentCase) {
    currentAIContext.value = {
      case: currentCase,
      lastAction: recentActions.value[0],
      schedule: todaySchedule.value,
      currentTime: new Date(),
      performance: stats.value
    }
  }
}

const handleAISuggestion = (suggestion) => {
  console.log('AI提案実行:', suggestion)
  
  switch (suggestion.id) {
    case 'immediate_call':
    case 'call_now':
      if (currentAIContext.value?.case) {
        makeCall(currentAIContext.value.case)
      }
      break
      
    case 'schedule_optimal':
    case 'priority_schedule':
      if (currentAIContext.value?.case) {
        scheduleVisit(currentAIContext.value.case)
      }
      break
      
    case 'execute_action':
      // 推奨アクションの実行
      if (suggestion.details?.method === 'phone') {
        makeCall(currentAIContext.value?.case)
      } else if (suggestion.details?.method === 'sms') {
        sendSMS(currentAIContext.value?.case)
      } else if (suggestion.details?.method === 'visit') {
        scheduleVisit(currentAIContext.value?.case)
      }
      break
      
    default:
      alert(`AI提案「${suggestion.label}」の実行機能は実装予定です`)
      break
  }
}

const requestAIAction = (actionType) => {
  console.log('AIアクション要求:', actionType)
  // AIからの要求に応じたアクション実行
}

// ラベル取得関数
const getStatusLabel = (status) => {
  const labels = {
    new: '新規',
    contacted: '連絡済',
    visited: '訪問済',
    quoted: '見積済'
  }
  return labels[status] || status
}

const getPriorityLabel = (priority) => {
  const labels = {
    high: '至急',
    medium: '通常',
    low: '低'
  }
  return labels[priority] || priority
}

const getNextActionLabel = (type) => {
  const labels = {
    call: '📞 電話予定',
    visit: '🏠 訪問予定',
    contract: '📄 契約予定',
    follow: '📧 フォロー'
  }
  return labels[type] || type
}


// 日時フォーマット関数
const formatDate = (date) => {
  if (!date) return '-'
  return new Date(date).toLocaleDateString('ja-JP', {
    month: 'short',
    day: 'numeric'
  })
}

const formatDateTime = (date) => {
  if (!date) return '-'
  return new Date(date).toLocaleString('ja-JP', {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  })
}

