<script setup>
import { ref, computed, onMounted } from 'vue'
import { useAuthStore } from '@/stores/auth'
import { useInquiriesStore } from '@/stores/inquiries'
import { useBillingStore } from '@/stores/billing'
import AppLayout from '@/components/Layout/AppLayout.vue'

// Stores
const authStore = useAuthStore()
const inquiriesStore = useInquiriesStore()
const billingStore = useBillingStore()

// モックデータ
const todayStats = ref({
  newInquiries: 5,
  pendingTasks: 12,
  urgentTasks: 3,
  completedToday: 8,
  monthlyRevenue: 2450000
})

const todayTasks = ref([
  {
    id: 1,
    title: '外壁塗装の現地調査',
    customer: '田中様',
    location: '東京都渋谷区',
    priority: 'high',
    deadline: '14:00'
  },
  {
    id: 2,
    title: '見積書作成',
    customer: '佐藤様',
    location: '神奈川県横浜市',
    priority: 'medium',
    deadline: '17:00'
  },
  {
    id: 3,
    title: '工事完了報告',
    customer: '鈴木様',
    location: '東京都新宿区',
    priority: 'low',
    deadline: '18:00'
  }
])

const recentInquiries = ref([
  {
    id: 1,
    title: 'マンション外壁塗装',
    customer: '山田様',
    status: 'new',
    createdAt: '10:30'
  },
  {
    id: 2,
    title: '戸建て屋根修繕',
    customer: '高橋様',
    status: 'in_progress',
    createdAt: '09:15'
  },
  {
    id: 3,
    title: 'ベランダ防水工事',
    customer: '伊藤様',
    status: 'quoted',
    createdAt: '昨日'
  }
])

// Computed
const currentDate = computed(() => {
  const today = new Date()
  return today.toLocaleDateString('ja-JP', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    weekday: 'long'
  })
})

// Methods
const formatNumber = (num) => {
  return num.toLocaleString('ja-JP')
}

const getPriorityLabel = (priority) => {
  const labels = {
    high: '緊急',
    medium: '通常',
    low: '低'
  }
  return labels[priority] || '通常'
}

const getStatusLabel = (status) => {
  const labels = {
    new: '新規',
    in_progress: '対応中',
    quoted: '見積済',
    completed: '完了'
  }
  return labels[status] || '不明'
}

// ダッシュボード統計を計算
const dashboardStats = computed(() => {
  const inquiryStats = inquiriesStore.statusCounts
  const billingStats = billingStore.summary
  
  return {
    newInquiries: inquiryStats.new || 0,
    pendingTasks: inquiryStats.in_progress || 0,
    completedToday: inquiryStats.completed || 0,
    monthlyRevenue: billingStats.totalAmount || 0,
    urgentTasks: inquiriesStore.filteredInquiries.filter(i => i.priority === 'high').length || 0
  }
})

const refreshDashboard = async () => {
  const childId = authStore.user?.childId
  if (childId) {
    await Promise.all([
      inquiriesStore.fetchInquiries(childId),
      billingStore.fetchBillingRecords(childId)
    ])
  }
}

onMounted(() => {
  refreshDashboard()
})
</script>

