      <div class="modal-header">
        <div class="header-info">
          <h3>📞 電話アクション</h3>
          <p class="customer-info">{{ case_?.customerName || '未設定' }}様 - {{ case_?.title || '案件名未設定' }}</p>
        </div>
        <button @click="closeModal" class="modal-close">✕</button>
      </div>

      <!-- お客様情報 -->
      <div class="customer-details">
        <div class="detail-row">
          <span class="detail-label">📞 電話番号</span>
          <span class="detail-value">{{ case_?.phoneNumber || '未設定' }}</span>
          <button @click="copyToClipboard(case_?.phoneNumber || '')" class="copy-btn" title="コピー">
