          <span class="detail-value">{{ case_.title }}</span>
        </div>
      </div>

      <!-- AI提案 -->
      <div v-if="aiSuggestion" class="ai-suggestion">
        <div class="ai-icon">🤖</div>
        <div class="ai-content">
          <h4>AI通話アドバイス</h4>
          <p>{{ aiSuggestion.message }}</p>
          <div v-if="aiSuggestion.talkingPoints" class="talking-points">
            <strong>話すポイント:</strong>
            <ul>
              <li v-for="point in aiSuggestion.talkingPoints" :key="point">{{ point }}</li>
            </ul>
          </div>
        </div>
      </div>

      <!-- アクションボタン -->
      <div class="action-section">
        <div class="primary-actions">
          <button 
            @click="startCall" 
            class="btn btn-primary btn-lg call-btn"
            :disabled="isProcessing"
          >
            <span class="btn-icon">📞</span>
            電話をかける
          </button>
          
          <button 
            @click="markAsUnavailable" 
            class="btn btn-secondary btn-lg"
            :disabled="isProcessing"
          >
            <span class="btn-icon">📵</span>
            不在・不通
          </button>
        </div>
      </div>

      <!-- 通話中・通話後 -->
      <div v-if="callInProgress || callCompleted" class="call-status">
        <!-- 通話中 -->
        <div v-if="callInProgress" class="calling-status">
          <div class="calling-animation">
            <div class="pulse-ring"></div>
            <div class="pulse-ring"></div>
            <div class="pulse-ring"></div>
            <span class="call-icon">📞</span>
          </div>
          <h4>通話中...</h4>
          <p>{{ case_?.customerName || '未設定' }}様</p>
          <div class="call-timer">{{ formatCallTime(callDuration) }}</div>
          <button @click="endCall" class="btn btn-danger">
            通話終了
          </button>
        </div>

        <!-- 通話後 -->
        <div v-if="callCompleted" class="call-completed">
          <h4>🎉 通話完了</h4>
          <p>通話時間: {{ formatCallTime(finalCallDuration) }}</p>
          
          <!-- 通話結果選択 -->
          <div class="call-result">
            <h5>通話結果を選択してください:</h5>
            <div class="result-options">
              <button 
                v-for="result in callResults" 
                :key="result.id"
                @click="selectCallResult(result)"
                class="result-btn"
                :class="{ active: selectedResult?.id === result.id }"
              >
                <span class="result-icon">{{ result.icon }}</span>
                <span class="result-text">{{ result.label }}</span>
              </button>
            </div>
          </div>

          <!-- メモ入力 -->
          <div class="memo-section">
            <label>通話メモ (任意):</label>
            <textarea 
              v-model="callMemo"
              class="memo-input"
              placeholder="通話内容、お客様の反応、次回のアクションなどを記録してください..."
              rows="4"
            ></textarea>
          </div>

          <!-- 次回アクション提案 -->
          <div v-if="selectedResult && nextActionSuggestions.length > 0" class="next-action-suggestions">
            <h5>🤖 次回アクション提案:</h5>
            <div class="suggestion-buttons">
              <button 
                v-for="suggestion in nextActionSuggestions"
                :key="suggestion.id"
                @click="selectNextAction(suggestion)"
                class="suggestion-btn"
                :class="{ active: selectedNextAction?.id === suggestion.id }"
              >
                <span class="suggestion-icon">{{ suggestion.icon }}</span>
                <span class="suggestion-text">{{ suggestion.label }}</span>
                <span class="suggestion-time">{{ suggestion.timeLabel }}</span>
              </button>
            </div>
          </div>

          <!-- 完了ボタン -->
          <div class="completion-actions">
            <button 
              @click="saveCallLog"
              class="btn btn-success btn-lg"
              :disabled="!selectedResult || isSaving"
            >
              <span v-if="isSaving" class="loading-spinner"></span>
              <span v-else class="btn-icon">✅</span>
              記録して完了
            </button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch } from 'vue'

const props = defineProps({
  show: Boolean,
  case: Object
})

const emit = defineEmits(['close', 'call-completed'])

// リアクティブデータ
const isProcessing = ref(false)
const callInProgress = ref(false)
const callCompleted = ref(false)
const callDuration = ref(0)
const finalCallDuration = ref(0)
const callTimer = ref(null)
const selectedResult = ref(null)
const selectedNextAction = ref(null)
const callMemo = ref('')
const isSaving = ref(false)

// AI提案
const aiSuggestion = computed(() => {
  if (!props.case) return null
  
  // 案件情報に基づくAI提案
  const suggestions = {
    '外壁塗装': {
      message: '築年数と前回塗装時期を確認し、緊急度を判断してください。',
      talkingPoints: [
        '築年数と前回塗装時期の確認',
        '現在困っている症状の詳細',
        '予算感の確認',
        '現地調査の日程調整'
      ]
    },
    '屋根修繕': {
      message: '雨漏りなど緊急性の高い案件の可能性があります。迅速な対応をアピールしてください。',
      talkingPoints: [
        '雨漏りの有無と緊急度',
        '台風や天候への備え',
        '応急処置の必要性',
        '早期現地調査の提案'
      ]
    }
  }
  
  const workType = Object.keys(suggestions).find(type => 
    props.case?.title?.includes(type)
  )
  
  return suggestions[workType] || {
    message: 'お客様のニーズを丁寧にヒアリングし、信頼関係を築いてください。',
    talkingPoints: [
      '工事内容の詳細確認',
      '予算と工期の相談',
      '不安や疑問点の解消',
      '次回アクションの提案'
    ]
  }
})

// 通話結果オプション
const callResults = [
  { id: 'answered_positive', icon: '😊', label: '応対良好', color: 'success' },
  { id: 'answered_neutral', icon: '😐', label: '普通の応対', color: 'info' },
  { id: 'answered_negative', icon: '😞', label: '興味薄い', color: 'warning' },
  { id: 'no_answer', icon: '📵', label: '不在・不通', color: 'secondary' },
  { id: 'busy', icon: '⏰', label: '忙しい・後で', color: 'warning' },
  { id: 'wrong_number', icon: '❌', label: '間違い電話', color: 'danger' }
]

// 次回アクション提案
const nextActionSuggestions = computed(() => {
  if (!selectedResult.value) return []
  
  const suggestions = {
    'answered_positive': [
      { id: 'visit_tomorrow', icon: '🏠', label: '現地調査', timeLabel: '明日', type: 'visit', hours: 24 },
      { id: 'call_followup', icon: '📞', label: 'フォロー電話', timeLabel: '3日後', type: 'call', hours: 72 },
      { id: 'send_info', icon: '📧', label: '資料送付', timeLabel: '今日', type: 'email', hours: 2 }
    ],
    'answered_neutral': [
      { id: 'call_later', icon: '📞', label: '再度電話', timeLabel: '1週間後', type: 'call', hours: 168 },
      { id: 'send_info', icon: '📧', label: '資料送付', timeLabel: '今日', type: 'email', hours: 2 },
      { id: 'visit_later', icon: '🏠', label: '現地調査', timeLabel: '来週', type: 'visit', hours: 168 }
    ],
    'answered_negative': [
      { id: 'call_much_later', icon: '📞', label: '再度電話', timeLabel: '1ヶ月後', type: 'call', hours: 720 },
      { id: 'send_light_info', icon: '📧', label: '軽い情報提供', timeLabel: '1週間後', type: 'email', hours: 168 }
    ],
    'no_answer': [
      { id: 'call_again', icon: '📞', label: '再度電話', timeLabel: '明日', type: 'call', hours: 24 },
      { id: 'call_evening', icon: '📞', label: '夕方に電話', timeLabel: '今日夕方', type: 'call', hours: 6 },
      { id: 'send_sms', icon: '💬', label: 'SMS送信', timeLabel: '30分後', type: 'sms', hours: 0.5 }
    ],
    'busy': [
      { id: 'call_later_today', icon: '📞', label: '再度電話', timeLabel: '夕方', type: 'call', hours: 6 },
      { id: 'call_tomorrow', icon: '📞', label: '明日電話', timeLabel: '明日', type: 'call', hours: 24 },
      { id: 'send_sms', icon: '💬', label: 'SMS送信', timeLabel: '1時間後', type: 'sms', hours: 1 }
    ],
    'wrong_number': [
      { id: 'update_contact', icon: '📝', label: '連絡先確認', timeLabel: 'すぐ', type: 'update', hours: 0 }
    ]
  }
  
  return suggestions[selectedResult.value.id] || []
})

// メソッド
const closeModal = () => {
  resetModal()
  emit('close')
}

const resetModal = () => {
  callInProgress.value = false
  callCompleted.value = false
  callDuration.value = 0
  finalCallDuration.value = 0
  selectedResult.value = null
  selectedNextAction.value = null
  callMemo.value = ''
  if (callTimer.value) {
    clearInterval(callTimer.value)
    callTimer.value = null
  }
}

const copyToClipboard = async (text) => {
  try {
    await navigator.clipboard.writeText(text)
    alert('電話番号をコピーしました')
  } catch (err) {
    console.error('コピーに失敗:', err)
  }
}

const startCall = () => {
  isProcessing.value = true
  callInProgress.value = true
  callDuration.value = 0
  
  // 通話タイマー開始
  callTimer.value = setInterval(() => {
    callDuration.value++
  }, 1000)
  
  // 実際の電話発信（プラットフォームに依存）
  if (props.case?.phoneNumber) {
    window.location.href = `tel:${props.case.phoneNumber}`
  }
  
  isProcessing.value = false
}

const endCall = () => {
  callInProgress.value = false
  callCompleted.value = true
  finalCallDuration.value = callDuration.value
  
  if (callTimer.value) {
    clearInterval(callTimer.value)
    callTimer.value = null
  }
}

const markAsUnavailable = () => {
  selectedResult.value = callResults.find(r => r.id === 'no_answer')
  callCompleted.value = true
  finalCallDuration.value = 0
}

const selectCallResult = (result) => {
  selectedResult.value = result
  selectedNextAction.value = null // リセット
}

const selectNextAction = (action) => {
  selectedNextAction.value = action
}

const saveCallLog = async () => {
  isSaving.value = true
  
  try {
    const logData = {
      caseId: props.case?.id,
      actionType: 'call',
      result: selectedResult.value.id,
      duration: finalCallDuration.value,
      memo: callMemo.value,
      nextAction: selectedNextAction.value,
      timestamp: new Date().toISOString()
    }
    
    // ログ保存API呼び出し（実装予定）
    console.log('通話ログ保存:', logData)
    
    // 成功メッセージ
    alert('✅ 通話ログを保存しました！')
    
    // 親コンポーネントに完了を通知
    emit('call-completed', logData)
    
    closeModal()
  } catch (error) {
    console.error('ログ保存エラー:', error)
    alert('❌ ログの保存に失敗しました')
  } finally {
    isSaving.value = false
  }
}

const formatCallTime = (seconds) => {
  const minutes = Math.floor(seconds / 60)
  const remainingSeconds = seconds % 60
  return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`
}

// ウォッチャー
watch(() => props.show, (newValue) => {
  if (newValue) {
    resetModal()
  }
})
</script>

