<template>
  <div id="app">
    <router-view />
  </div>
</template>

<script setup>
import { onMounted } from 'vue'
import { useAuthStore } from '@/stores/auth'

const authStore = useAuthStore()

onMounted(() => {
  // 管理者認証をチェック（URLパラメータから）
  const hasAdminAccess = authStore.checkAdminAccess()
  
  if (!hasAdminAccess) {
    // 通常の認証状態を確認
    if (authStore.token) {
      authStore.fetchUser()
    }
  }
})
</script>

<style>
/* App specific styles */
#app {
  min-height: 100vh;
}
</style>
